-- TOC entry 243 (class 1255 OID 17442)
-- Name: compute_influent_score(character varying, double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.compute_influent_score(p_user_id character varying, p_alpha double precision DEFAULT 0.33, p_beta double precision DEFAULT 0.33, p_gamma double precision DEFAULT 0.34) RETURNS TABLE(user_id character varying, sentiment_component double precision, engagement_component double precision, connection_component double precision, influent_score double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH sentiment_comp AS (
        SELECT 
            p_user_id as uid,
            COALESCE(avg_sentiment * (1 - LEAST(sentiment_variance, 1.0)), 0.5) as S
        FROM user_sentiment_stats
        WHERE user_sentiment_stats.user_id = p_user_id
    ),
    engagement_comp AS (
        SELECT 
            p_user_id as uid,
            LEAST(1.0, COALESCE(
                SUM(avg_sentiment * (total_likes + 2*total_replies + 3*total_retweets)) / 10000.0,
                0
            )) as E
        FROM engagement_features
        WHERE to_user = p_user_id
    ),
    connection_comp AS (
        SELECT 
            p_user_id as uid,
            COALESCE(AVG(weight), 0) as C
        FROM connection_weights
        WHERE to_user = p_user_id
    )
    SELECT 
        p_user_id,
        COALESCE(sc.S, 0.5) as sentiment_component,
        COALESCE(ec.E, 0.0) as engagement_component,
        COALESCE(cc.C, 0.0) as connection_component,
        (p_alpha * COALESCE(sc.S, 0.5) + 
         p_beta * COALESCE(ec.E, 0.0) + 
         p_gamma * COALESCE(cc.C, 0.0)) as influent_score
    FROM sentiment_comp sc
    FULL OUTER JOIN engagement_comp ec ON sc.uid = ec.uid
    FULL OUTER JOIN connection_comp cc ON sc.uid = cc.uid;
END;
$$;


