-- Name: user_sentiment_stats; Type: MATERIALIZED VIEW; Schema: public; Owner: postgres
--

CREATE MATERIALIZED VIEW public.user_sentiment_stats AS
 SELECT user_id,
    avg(norm_sentiment) AS avg_sentiment,
    stddev(norm_sentiment) AS sentiment_variance,
    count(*) AS total_posts_analyzed,
    sum(
        CASE
            WHEN (norm_sentiment > (0.6)::double precision) THEN 1
            ELSE 0
        END) AS positive_posts,
    sum(
        CASE
            WHEN (norm_sentiment < (0.4)::double precision) THEN 1
            ELSE 0
        END) AS negative_posts,
    sum(
        CASE
            WHEN ((norm_sentiment >= (0.4)::double precision) AND (norm_sentiment <= (0.6)::double precision)) THEN 1
            ELSE 0
        END) AS neutral_posts
   FROM public.sentiment_scores
  GROUP BY user_id
  WITH NO DATA;


