-- Name: top_influencers; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.top_influencers AS
 WITH sentiment_component AS (
         SELECT user_sentiment_stats.user_id,
            COALESCE((user_sentiment_stats.avg_sentiment * ((1)::double precision - LEAST(user_sentiment_stats.sentiment_variance, (1.0)::double precision))), (0.5)::double precision) AS s
           FROM public.user_sentiment_stats
        ), engagement_component AS (
         SELECT engagement_features.to_user AS user_id,
            LEAST((1.0)::double precision, COALESCE((sum((engagement_features.avg_sentiment * (((engagement_features.total_likes + (2 * engagement_features.total_replies)) + (3 * engagement_features.total_retweets)))::double precision)) / (10000.0)::double precision), (0)::double precision)) AS e
           FROM public.engagement_features
          GROUP BY engagement_features.to_user
        ), connection_component AS (
         SELECT connection_weights.to_user AS user_id,
            COALESCE(avg(connection_weights.weight), (0)::double precision) AS c
           FROM public.connection_weights
          GROUP BY connection_weights.to_user
        )
 SELECT u.user_id,
    u.display_name,
    u.followers,
    u.is_verified,
    COALESCE(sc.s, (0.5)::double precision) AS sentiment_score,
    COALESCE(ec.e, (0)::double precision) AS engagement_score,
    COALESCE(cc.c, (0)::double precision) AS connection_score,
    ((((0.33)::double precision * COALESCE(sc.s, (0.5)::double precision)) + ((0.33)::double precision * COALESCE(ec.e, (0)::double precision))) + ((0.34)::double precision * COALESCE(cc.c, (0)::double precision))) AS influent_score
   FROM (((public.twitter_users u
     LEFT JOIN sentiment_component sc ON (((u.user_id)::text = (sc.user_id)::text)))
     LEFT JOIN engagement_component ec ON (((u.user_id)::text = (ec.user_id)::text)))
     LEFT JOIN connection_component cc ON (((u.user_id)::text = (cc.user_id)::text)))
  ORDER BY ((((0.33)::double precision * COALESCE(sc.s, (0.5)::double precision)) + ((0.33)::double precision * COALESCE(ec.e, (0)::double precision))) + ((0.34)::double precision * COALESCE(cc.c, (0)::double precision))) DESC;


